"use client"

import { SocialFeedUI, type SocialFeedUIProps } from "./social-feed-ui"
import {
  useSocialFeed,
  type UseSocialFeedOptions,
  type UseSocialFeedReturn,
  type SocialPost,
  type PostSigner,
  type AuthorProfile,
} from "./use-social-feed"

// ---------------------------------------------------------------------------
// Re-exports
// ---------------------------------------------------------------------------

export { PostCardUI, type PostCardUIProps } from "./post-card-ui"
export { SocialFeedUI, type SocialFeedUIProps } from "./social-feed-ui"
export {
  useSocialFeed,
  type UseSocialFeedOptions,
  type UseSocialFeedReturn,
  type SocialPost,
  type PostSigner,
  type AuthorProfile,
} from "./use-social-feed"

// ---------------------------------------------------------------------------
// Types
// ---------------------------------------------------------------------------

export interface SocialFeedProps
  extends Omit<
    SocialFeedUIProps,
    | "posts"
    | "isLoading"
    | "isLoadingMore"
    | "error"
    | "hasMore"
    | "onLoadMore"
    | "onRefresh"
  > {
  /** Channel to filter posts by */
  channel?: string
  /** Search query string */
  query?: string
  /** Number of posts per page (default: 20) */
  limit?: number
  /** Base URL for the 1sat-stack API (default: https://api.1sat.app) */
  apiUrl?: string
  /** Whether to auto-fetch on mount (default: true) */
  autoFetch?: boolean
}

// ---------------------------------------------------------------------------
// Composed component
// ---------------------------------------------------------------------------

/**
 * A chronological feed of on-chain BSocial posts.
 *
 * Fetches posts from the 1sat-stack API and renders them in a vertical feed
 * with avatar, author name, timestamp, content, and action buttons.
 * Supports infinite scroll pagination, channel filtering, and custom
 * like button rendering via the `renderLikeButton` prop.
 *
 * @example
 * ```tsx
 * import { SocialFeed } from "@/components/blocks/social-feed"
 *
 * <SocialFeed
 *   channel="general"
 *   onPostClick={(post) => console.log("Clicked:", post.txid)}
 *   onAuthorClick={(post) => console.log("Author:", post.signers?.[0])}
 * />
 * ```
 *
 * @example
 * ```tsx
 * // With custom like button
 * import { SocialFeed } from "@/components/blocks/social-feed"
 * import { LikeButton } from "@/components/blocks/like-button"
 *
 * <SocialFeed
 *   renderLikeButton={(post) => (
 *     <LikeButton
 *       txid={post.txid}
 *       count={post.likes ?? 0}
 *       variant="text"
 *       onLike={async (txid) => {
 *         // broadcast BSocial like tx
 *         return { txid: "..." }
 *       }}
 *     />
 *   )}
 * />
 * ```
 */
export function SocialFeed({
  channel,
  query,
  limit,
  apiUrl,
  autoFetch,
  ...uiProps
}: SocialFeedProps) {
  const feed = useSocialFeed({
    channel,
    query,
    limit,
    apiUrl,
    autoFetch,
  })

  return (
    <SocialFeedUI
      posts={feed.posts}
      isLoading={feed.isLoading}
      isLoadingMore={feed.isLoadingMore}
      error={feed.error}
      hasMore={feed.hasMore}
      onLoadMore={feed.loadMore}
      onRefresh={feed.refresh}
      {...uiProps}
    />
  )
}

"use client"

import { cn } from "@/lib/utils"
import { Avatar, AvatarFallback, AvatarImage } from "@/components/ui/avatar"
import { Badge } from "@/components/ui/badge"
import { Heart, MessageCircle, ExternalLink } from "lucide-react"
import type { SocialPost } from "./use-social-feed"

// ---------------------------------------------------------------------------
// Types
// ---------------------------------------------------------------------------

export interface PostCardUIProps {
  /** The post data to render */
  post: SocialPost
  /** Optional CSS classes */
  className?: string
  /** Called when the post card is clicked */
  onPostClick?: (post: SocialPost) => void
  /** Called when the author row is clicked */
  onAuthorClick?: (post: SocialPost) => void
  /** Slot for a custom like button component (e.g. the LikeButton block) */
  likeButtonSlot?: React.ReactNode
  /** Whether to show the reply button */
  showReplyButton?: boolean
  /** Called when the reply button is clicked */
  onReplyClick?: (post: SocialPost) => void
  /** Callback to handle external links (e.g. open in system browser from a WebView) */
  onExternalLink?: (url: string) => void
}

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

/** Format a unix timestamp (seconds) to a relative time string */
function formatRelativeTime(timestampSeconds: number): string {
  const now = Date.now() / 1000
  const diff = now - timestampSeconds

  if (diff < 60) return "just now"
  if (diff < 3600) {
    const mins = Math.floor(diff / 60)
    return `${mins}m ago`
  }
  if (diff < 86400) {
    const hours = Math.floor(diff / 3600)
    return `${hours}h ago`
  }
  if (diff < 604800) {
    const days = Math.floor(diff / 86400)
    return `${days}d ago`
  }

  const date = new Date(timestampSeconds * 1000)
  return date.toLocaleDateString(undefined, {
    month: "short",
    day: "numeric",
    year:
      date.getFullYear() !== new Date().getFullYear() ? "numeric" : undefined,
  })
}

/** Derive a display name from a post's signer or author data */
function getDisplayName(post: SocialPost): string {
  if (post.author?.name) return post.author.name
  if (post.signers?.[0]?.bapId) {
    const bapId = post.signers[0].bapId
    return `${bapId.slice(0, 6)}...${bapId.slice(-4)}`
  }
  if (post.signers?.[0]?.address) {
    const addr = post.signers[0].address
    return `${addr.slice(0, 6)}...${addr.slice(-4)}`
  }
  return "Anonymous"
}

/** Derive initials for the avatar fallback */
function getInitials(name: string): string {
  if (name === "Anonymous") return "?"
  // If it looks like a truncated hash/address, use the first two chars
  if (name.includes("...")) return name.slice(0, 2).toUpperCase()
  const parts = name.trim().split(/\s+/)
  if (parts.length >= 2) {
    return `${parts[0][0]}${parts[1][0]}`.toUpperCase()
  }
  return name.slice(0, 2).toUpperCase()
}

/** Build an ORDFS URL for embedded media */
function getMediaUrl(outpoint: string): string {
  return `https://ordfs.network/content/${outpoint}`
}

// ---------------------------------------------------------------------------
// Component
// ---------------------------------------------------------------------------

export function PostCardUI({
  post,
  className,
  onPostClick,
  onAuthorClick,
  likeButtonSlot,
  showReplyButton = true,
  onReplyClick,
  onExternalLink,
}: PostCardUIProps) {
  const displayName = getDisplayName(post)
  const initials = getInitials(displayName)
  const avatarUrl = post.author?.avatar
  const isClickable = Boolean(onPostClick)

  return (
    <article
      className={cn(
        "group relative flex gap-3 px-4 py-3",
        isClickable &&
          "cursor-pointer hover:bg-accent/50 transition-colors duration-150",
        className
      )}
      onClick={onPostClick ? () => onPostClick(post) : undefined}
      role={isClickable ? "button" : undefined}
      tabIndex={isClickable ? 0 : undefined}
      onKeyDown={
        isClickable
          ? (e) => {
              if (e.key === "Enter" || e.key === " ") {
                e.preventDefault()
                onPostClick?.(post)
              }
            }
          : undefined
      }
      data-testid="post-card"
    >
      {/* Avatar column */}
      <div className="shrink-0 pt-0.5">
        <button
          type="button"
          className="rounded-full focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2"
          onClick={(e) => {
            e.stopPropagation()
            onAuthorClick?.(post)
          }}
          disabled={!onAuthorClick}
          aria-label={`View profile of ${displayName}`}
        >
          <Avatar className="size-8">
            {avatarUrl && <AvatarImage src={avatarUrl} alt={displayName} />}
            <AvatarFallback>{initials}</AvatarFallback>
          </Avatar>
        </button>
      </div>

      {/* Content column */}
      <div className="flex-1 min-w-0 flex flex-col gap-1.5">
        {/* Author row */}
        <div className="flex items-center gap-2 min-w-0">
          <button
            type="button"
            className={cn(
              "truncate text-sm font-semibold text-foreground",
              onAuthorClick &&
                "hover:underline focus-visible:outline-none focus-visible:underline"
            )}
            onClick={(e) => {
              e.stopPropagation()
              onAuthorClick?.(post)
            }}
            disabled={!onAuthorClick}
          >
            {displayName}
          </button>

          {post.channel && (
            <Badge
              variant="secondary"
              className="shrink-0 text-[10px] leading-tight px-1.5 py-0"
            >
              #{post.channel}
            </Badge>
          )}

          <time
            dateTime={new Date(post.timestamp * 1000).toISOString()}
            className="shrink-0 text-xs text-muted-foreground ml-auto"
            title={new Date(post.timestamp * 1000).toLocaleString()}
          >
            {formatRelativeTime(post.timestamp)}
          </time>
        </div>

        {/* Post content */}
        <div className="text-sm text-foreground whitespace-pre-wrap break-words leading-relaxed">
          {post.content}
        </div>

        {/* Embedded media */}
        {post.mediaOutpoint && (
          <div className="mt-2 overflow-hidden rounded-lg border border-border">
            <img
              src={getMediaUrl(post.mediaOutpoint)}
              alt="Embedded media"
              className="max-h-80 w-auto object-contain"
              loading="lazy"
            />
          </div>
        )}

        {/* Action bar */}
        <div className="flex items-center gap-1 pt-1 -ml-1.5">
          {/* Like button slot or default */}
          {likeButtonSlot ?? (
            <span
              className={cn(
                "inline-flex items-center gap-1 rounded-full px-2 py-1 text-xs text-muted-foreground",
                "transition-colors duration-150"
              )}
              aria-label={`${post.likes ?? 0} likes`}
            >
              <Heart className="size-3.5" aria-hidden="true" />
              {(post.likes ?? 0) > 0 && (
                <span className="tabular-nums">{post.likes}</span>
              )}
            </span>
          )}

          {/* Reply button */}
          {showReplyButton && (
            <button
              type="button"
              className={cn(
                "inline-flex items-center gap-1 rounded-full px-2 py-1 text-xs text-muted-foreground",
                "hover:bg-accent hover:text-accent-foreground transition-colors duration-150",
                "focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring"
              )}
              onClick={(e) => {
                e.stopPropagation()
                onReplyClick?.(post)
              }}
              disabled={!onReplyClick}
              aria-label={`${post.replies ?? 0} replies`}
            >
              <MessageCircle className="size-3.5" aria-hidden="true" />
              {(post.replies ?? 0) > 0 && (
                <span className="tabular-nums">{post.replies}</span>
              )}
            </button>
          )}

          {/* View on-chain link */}
          {onExternalLink ? (
            <button
              type="button"
              className={cn(
                "inline-flex items-center gap-1 rounded-full px-2 py-1 text-xs text-muted-foreground",
                "hover:bg-accent hover:text-accent-foreground transition-colors duration-150",
                "focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring",
                "ml-auto"
              )}
              onClick={(e) => {
                e.stopPropagation()
                onExternalLink(`https://whatsonchain.com/tx/${post.txid}`)
              }}
              aria-label="View transaction on-chain"
            >
              <ExternalLink className="size-3" aria-hidden="true" />
            </button>
          ) : (
            <a
              href={`https://whatsonchain.com/tx/${post.txid}`}
              target="_blank"
              rel="noopener noreferrer"
              className={cn(
                "inline-flex items-center gap-1 rounded-full px-2 py-1 text-xs text-muted-foreground",
                "hover:bg-accent hover:text-accent-foreground transition-colors duration-150",
                "focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring",
                "ml-auto"
              )}
              onClick={(e) => e.stopPropagation()}
              aria-label="View transaction on-chain"
            >
              <ExternalLink className="size-3" aria-hidden="true" />
            </a>
          )}
        </div>
      </div>
    </article>
  )
}

"use client"

import { useCallback, useEffect, useRef } from "react"
import { cn } from "@/lib/utils"
import { Button } from "@/components/ui/button"
import { Separator } from "@/components/ui/separator"
import { Skeleton } from "@/components/ui/skeleton"
import { AlertCircle, Loader2, MessageSquare, RefreshCw } from "lucide-react"
import { PostCardUI, type PostCardUIProps } from "./post-card-ui"
import type { SocialPost } from "./use-social-feed"

// ---------------------------------------------------------------------------
// Types
// ---------------------------------------------------------------------------

export interface SocialFeedUIProps {
  /** Array of posts to display */
  posts: SocialPost[]
  /** Whether the initial fetch is in progress */
  isLoading: boolean
  /** Whether a "load more" request is in progress */
  isLoadingMore: boolean
  /** Error from the most recent fetch */
  error: Error | null
  /** Whether more posts are available to load */
  hasMore: boolean
  /** Fetch the next page of posts */
  onLoadMore: () => void
  /** Re-fetch the feed from the beginning */
  onRefresh: () => void
  /** Optional CSS classes for the outer container */
  className?: string
  /** Called when a post card is clicked */
  onPostClick?: (post: SocialPost) => void
  /** Called when an author is clicked */
  onAuthorClick?: (post: SocialPost) => void
  /** Called when the reply button is clicked */
  onReplyClick?: (post: SocialPost) => void
  /** Whether to use IntersectionObserver for infinite scroll (default: true) */
  infiniteScroll?: boolean
  /** Render function for a custom like button per post */
  renderLikeButton?: (post: SocialPost) => React.ReactNode
  /** Render function for custom post card content */
  renderPostCard?: (
    post: SocialPost,
    defaultProps: PostCardUIProps
  ) => React.ReactNode
  /** Callback to handle external links (e.g. open in system browser from a WebView) */
  onExternalLink?: (url: string) => void
}

// ---------------------------------------------------------------------------
// Skeleton loader
// ---------------------------------------------------------------------------

function PostCardSkeleton() {
  return (
    <div className="flex gap-3 px-4 py-3" data-testid="post-card-skeleton">
      <Skeleton className="size-8 rounded-full shrink-0" />
      <div className="flex flex-1 flex-col gap-2">
        <div className="flex items-center gap-2">
          <Skeleton className="h-4 w-24" />
          <Skeleton className="h-3 w-12 ml-auto" />
        </div>
        <Skeleton className="h-4 w-full" />
        <Skeleton className="h-4 w-3/4" />
        <div className="flex gap-3 pt-1">
          <Skeleton className="size-5 rounded-full" />
          <Skeleton className="size-5 rounded-full" />
        </div>
      </div>
    </div>
  )
}

// ---------------------------------------------------------------------------
// Empty state
// ---------------------------------------------------------------------------

function EmptyState({ onRefresh }: { onRefresh: () => void }) {
  return (
    <div
      className="flex flex-col items-center justify-center py-16 px-4 text-center"
      data-testid="social-feed-empty"
    >
      <div className="mx-auto mb-4 flex size-12 items-center justify-center rounded-full bg-muted">
        <MessageSquare className="size-6 text-muted-foreground" />
      </div>
      <p className="text-sm font-medium text-foreground">No posts yet</p>
      <p className="mt-1 text-sm text-muted-foreground">
        Be the first to post something on-chain
      </p>
      <Button variant="outline" size="sm" className="mt-4" onClick={onRefresh}>
        <RefreshCw data-icon="inline-start" />
        Refresh
      </Button>
    </div>
  )
}

// ---------------------------------------------------------------------------
// Error state
// ---------------------------------------------------------------------------

function ErrorState({
  error,
  onRetry,
}: {
  error: Error
  onRetry: () => void
}) {
  return (
    <div
      className="flex flex-col items-center justify-center py-12 px-4 text-center"
      role="alert"
      data-testid="social-feed-error"
    >
      <div className="mx-auto mb-4 flex size-12 items-center justify-center rounded-full bg-destructive/10">
        <AlertCircle className="size-6 text-destructive" />
      </div>
      <p className="text-sm font-medium text-foreground">
        Failed to load posts
      </p>
      <p className="mt-1 text-sm text-muted-foreground max-w-sm">
        {error.message}
      </p>
      <Button variant="outline" size="sm" className="mt-4" onClick={onRetry}>
        Try again
      </Button>
    </div>
  )
}

// ---------------------------------------------------------------------------
// Component
// ---------------------------------------------------------------------------

export function SocialFeedUI({
  posts,
  isLoading,
  isLoadingMore,
  error,
  hasMore,
  onLoadMore,
  onRefresh,
  className,
  onPostClick,
  onAuthorClick,
  onReplyClick,
  infiniteScroll = true,
  renderLikeButton,
  renderPostCard,
  onExternalLink,
}: SocialFeedUIProps) {
  // Infinite scroll via IntersectionObserver
  const sentinelRef = useRef<HTMLDivElement>(null)

  const handleIntersect = useCallback(
    (entries: IntersectionObserverEntry[]) => {
      const entry = entries[0]
      if (entry?.isIntersecting && hasMore && !isLoading && !isLoadingMore) {
        onLoadMore()
      }
    },
    [hasMore, isLoading, isLoadingMore, onLoadMore]
  )

  useEffect(() => {
    if (!infiniteScroll) return
    const sentinel = sentinelRef.current
    if (!sentinel) return

    const observer = new IntersectionObserver(handleIntersect, {
      rootMargin: "200px",
    })
    observer.observe(sentinel)
    return () => observer.disconnect()
  }, [infiniteScroll, handleIntersect])

  // Initial loading state
  if (isLoading && posts.length === 0) {
    return (
      <div className={cn("divide-y divide-border", className)} data-testid="social-feed">
        <PostCardSkeleton />
        <PostCardSkeleton />
        <PostCardSkeleton />
      </div>
    )
  }

  // Error state (no posts loaded yet)
  if (error && posts.length === 0) {
    return (
      <div className={className} data-testid="social-feed">
        <ErrorState error={error} onRetry={onRefresh} />
      </div>
    )
  }

  // Empty state
  if (!isLoading && posts.length === 0) {
    return (
      <div className={className} data-testid="social-feed">
        <EmptyState onRefresh={onRefresh} />
      </div>
    )
  }

  return (
    <div className={cn("relative", className)} data-testid="social-feed">
      {/* Post list */}
      <div className="divide-y divide-border">
        {posts.map((post) => {
          const defaultProps: PostCardUIProps = {
            post,
            onPostClick,
            onAuthorClick,
            onReplyClick,
            likeButtonSlot: renderLikeButton?.(post),
            onExternalLink,
          }

          return renderPostCard ? (
            <div key={post.txid}>{renderPostCard(post, defaultProps)}</div>
          ) : (
            <PostCardUI key={post.txid} {...defaultProps} />
          )
        })}
      </div>

      {/* Load more area */}
      <div className="py-4">
        {isLoadingMore && (
          <div className="flex items-center justify-center gap-2 py-3 text-sm text-muted-foreground">
            <Loader2 className="size-4 animate-spin" />
            Loading more posts...
          </div>
        )}

        {/* Error loading more (posts already visible) */}
        {error && posts.length > 0 && (
          <div className="flex items-center justify-center gap-2 py-3">
            <p className="text-sm text-destructive">{error.message}</p>
            <Button variant="ghost" size="sm" onClick={onLoadMore}>
              Retry
            </Button>
          </div>
        )}

        {/* Manual load more button (when infinite scroll is disabled) */}
        {!infiniteScroll && hasMore && !isLoadingMore && !error && (
          <div className="flex justify-center">
            <Button variant="outline" size="sm" onClick={onLoadMore}>
              Load more
            </Button>
          </div>
        )}

        {/* End of feed */}
        {!hasMore && posts.length > 0 && (
          <div className="flex items-center justify-center gap-3 py-2">
            <Separator className="flex-1 max-w-16" />
            <p className="text-xs text-muted-foreground">End of feed</p>
            <Separator className="flex-1 max-w-16" />
          </div>
        )}

        {/* Infinite scroll sentinel */}
        {infiniteScroll && hasMore && (
          <div ref={sentinelRef} className="h-1" aria-hidden="true" />
        )}
      </div>
    </div>
  )
}

import { useCallback, useEffect, useRef, useState } from "react"

// ---------------------------------------------------------------------------
// Types
// ---------------------------------------------------------------------------

/** A signer entry attached to a post (AIP identity) */
export interface PostSigner {
  /** Algorithm identifier (e.g. "BITCOIN_ECDSA") */
  algorithm: string
  /** Bitcoin address of the signer */
  address: string
  /** BAP identity ID, if present */
  bapId?: string
}

/** Author profile resolved from the BAP API */
export interface AuthorProfile {
  /** BAP identity ID */
  bapId: string
  /** Display name */
  name?: string
  /** Profile image URL or on-chain reference */
  avatar?: string
  /** Bitcoin address */
  address?: string
}

/** A single BSocial post as returned by the 1sat-stack API */
export interface SocialPost {
  /** Transaction ID of the post */
  txid: string
  /** Post content text */
  content: string
  /** Timestamp in seconds since epoch */
  timestamp: number
  /** App name from MAP protocol */
  app: string
  /** Action type (post, reply, etc.) */
  type: string
  /** Channel the post belongs to, if any */
  channel?: string
  /** Signer/author information from AIP */
  signers?: PostSigner[]
  /** Resolved author profile (populated client-side) */
  author?: AuthorProfile
  /** Number of likes on this post */
  likes?: number
  /** Number of replies to this post */
  replies?: number
  /** Media outpoint if post has embedded media */
  mediaOutpoint?: string
}

/** Raw post shape from 1sat-stack search endpoint */
interface RawSearchPost {
  txid: string
  B?: { content?: string; "content-type"?: string; encoding?: string }
  MAP?: {
    app?: string
    type?: string
    context?: string
    contextValue?: string
    channel?: string
  }
  timestamp?: number
  blk?: { t?: number }
  likes?: number
  replies?: number
}

/** Raw post shape from 1sat-stack address endpoint (includes signers) */
interface RawAddressPost extends RawSearchPost {
  AIP?: Array<{
    algorithm?: string
    address?: string
    bapId?: string
  }>
}

export interface UseSocialFeedOptions {
  /** Channel to filter posts by */
  channel?: string
  /** Search query string */
  query?: string
  /** Number of posts per page (default: 20) */
  limit?: number
  /** Base URL for the 1sat-stack API (default: https://api.1sat.app) */
  apiUrl?: string
  /** Whether to auto-fetch on mount (default: true) */
  autoFetch?: boolean
}

export interface UseSocialFeedReturn {
  /** Array of fetched posts */
  posts: SocialPost[]
  /** Whether the initial fetch is in progress */
  isLoading: boolean
  /** Whether a "load more" request is in progress */
  isLoadingMore: boolean
  /** Error from the most recent fetch, if any */
  error: Error | null
  /** Whether more posts are available beyond the current page */
  hasMore: boolean
  /** Fetch the next page of posts */
  loadMore: () => Promise<void>
  /** Re-fetch from the beginning */
  refresh: () => Promise<void>
}

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

const DEFAULT_API_URL = "https://api.1sat.app"
const DEFAULT_LIMIT = 20

function normalizePost(raw: RawSearchPost | RawAddressPost): SocialPost {
  const signers: PostSigner[] = []
  if ("AIP" in raw && Array.isArray(raw.AIP)) {
    for (const signer of raw.AIP) {
      signers.push({
        algorithm: signer.algorithm ?? "BITCOIN_ECDSA",
        address: signer.address ?? "",
        bapId: signer.bapId,
      })
    }
  }

  return {
    txid: raw.txid,
    content: raw.B?.content ?? "",
    timestamp: raw.blk?.t ?? raw.timestamp ?? 0,
    app: raw.MAP?.app ?? "bsocial",
    type: raw.MAP?.type ?? "post",
    channel: raw.MAP?.channel ?? raw.MAP?.contextValue,
    signers: signers.length > 0 ? signers : undefined,
    likes: raw.likes ?? 0,
    replies: raw.replies ?? 0,
  }
}

// ---------------------------------------------------------------------------
// Hook
// ---------------------------------------------------------------------------

export function useSocialFeed({
  channel,
  query,
  limit = DEFAULT_LIMIT,
  apiUrl = DEFAULT_API_URL,
  autoFetch = true,
}: UseSocialFeedOptions = {}): UseSocialFeedReturn {
  const [posts, setPosts] = useState<SocialPost[]>([])
  const [isLoading, setIsLoading] = useState(false)
  const [isLoadingMore, setIsLoadingMore] = useState(false)
  const [error, setError] = useState<Error | null>(null)
  const [hasMore, setHasMore] = useState(true)
  const offsetRef = useRef(0)
  const abortRef = useRef<AbortController | null>(null)

  const fetchPosts = useCallback(
    async (offset: number, isRefresh: boolean) => {
      abortRef.current?.abort()
      const controller = new AbortController()
      abortRef.current = controller

      if (isRefresh) {
        setIsLoading(true)
      } else {
        setIsLoadingMore(true)
      }
      setError(null)

      try {
        const params = new URLSearchParams()
        if (query) params.set("q", query)
        if (channel) params.set("channel", channel)
        params.set("limit", String(limit))
        params.set("offset", String(offset))

        const url = `${apiUrl}/1sat/bsocial/post/search?${params.toString()}`
        const response = await fetch(url, { signal: controller.signal })

        if (!response.ok) {
          throw new Error(
            `Failed to fetch posts: ${response.status} ${response.statusText}`
          )
        }

        const data: RawSearchPost[] = await response.json()
        const normalized = data.map(normalizePost)

        if (isRefresh) {
          setPosts(normalized)
        } else {
          setPosts((prev) => [...prev, ...normalized])
        }

        offsetRef.current = offset + normalized.length
        setHasMore(normalized.length >= limit)
      } catch (err) {
        if (err instanceof DOMException && err.name === "AbortError") return
        const fetchError =
          err instanceof Error ? err : new Error("Failed to fetch social feed")
        setError(fetchError)
      } finally {
        setIsLoading(false)
        setIsLoadingMore(false)
      }
    },
    [apiUrl, channel, limit, query]
  )

  const loadMore = useCallback(async () => {
    if (isLoadingMore || isLoading || !hasMore) return
    await fetchPosts(offsetRef.current, false)
  }, [fetchPosts, hasMore, isLoading, isLoadingMore])

  const refresh = useCallback(async () => {
    offsetRef.current = 0
    setHasMore(true)
    await fetchPosts(0, true)
  }, [fetchPosts])

  // Auto-fetch on mount and when dependencies change
  useEffect(() => {
    if (!autoFetch) return
    offsetRef.current = 0
    setHasMore(true)
    fetchPosts(0, true)

    return () => {
      abortRef.current?.abort()
    }
  }, [autoFetch, fetchPosts])

  return {
    posts,
    isLoading,
    isLoadingMore,
    error,
    hasMore,
    loadMore,
    refresh,
  }
}
